  happy_path_json = '["Start a sandbox checkout for the primary offer and selected order bump.","Receive trusted checkout.session.completed webhook evidence.","Update the checkout intent to paid.","Insert idempotent product_entitlements rows for mapped line items.","Queue public-safe fulfillment task evidence without returning signed URLs, R2 object keys, or private buyer data.","Open /products/entitlements with the checkout intent reference to confirm customer-safe entitlement and fulfillment status.","Create and consume a one-use download token that revalidates current entitlement and trusted checkout state before streaming the seeded private R2-backed fixture for a file entitlement.","Open /admin/products as a verified owner to inspect the entitlement rows and queued fulfillment evidence."]',
  edge_cases_json = '["Duplicate webhook events do not create duplicate entitlements.","Public /products/source-data exposes aggregate counts and redaction flags, not raw buyer rows.","A token created before a checkout state change is rejected while checkout state is no longer trusted paid or completed.","Arbitrary private asset uploads remain disabled.","Revocation, signed downloads, protected content, customer portal, refunds, and direct agent writes require later confirmed-write APIs.","Raw Stripe identifiers and buyer email remain server-private."]',
  agent_access = 'Agents can read /products/source-data, /api/products/entitlements, /api/products/download-tokens, and /commerce/source-data to understand the entitlement grant contract, customer-safe lookup, short-lived private R2-backed fixture delivery with redemption revalidation, and aggregate inspection counts. Owner sessions can inspect private buyer entitlement rows in /admin/products. Agents cannot grant, revoke, expose private buyer data, upload arbitrary assets, or issue signed object URLs without future authenticated confirmed-write APIs.',
  validation_json = '["Playwright covers source-data output, aggregate redaction, a paid test checkout webhook that creates entitlement rows, customer-safe lookup, private R2-backed token delivery, current checkout-state revalidation, replay rejection, owner /admin/products inspection, and duplicate webhook idempotency.","Issue #101 records the sandbox entitlement grant path.","Issue #139 records the owner product entitlement inspection path.","Issue #141 records the customer-safe product entitlement lookup path.","Issue #143 records the short-lived download-token path.","Issue #146 records the seeded private R2-backed fixture delivery path.","Issue #147 records token redemption revalidation against current entitlement and trusted checkout state."]',
